"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { Panel, Group, Separator } from "react-resizable-panels";
import { NewsItemData, IndexData, MarketStatusData, StatsData } from "./lib/types";
import {
  fetchNews,
  fetchStats,
  fetchIndices,
  fetchMarketStatus,
  createSSEConnection,
} from "./lib/api";
import { routeAllNews, RoutedNews, isHighImpactAlert } from "./lib/route-news";
import { playAlertSound } from "./lib/sounds";
import { Header } from "./components/Header";
import { HighImpactStrip } from "./components/HighImpactStrip";
import { SentimentDonut } from "./components/SentimentDonut";
import { NewsVelocity } from "./components/NewsVelocity";
import { NewsPanelCard } from "./components/NewsPanelCard";
import { WatchlistPanel } from "./components/WatchlistPanel";

const WATCHLIST_KEY = "paisamachine_watchlist";

function loadWatchlist(): string[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(WATCHLIST_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

export default function Home() {
  const [items, setItems] = useState<NewsItemData[]>([]);
  const [stats, setStats] = useState<StatsData | null>(null);
  const [indices, setIndices] = useState<IndexData[]>([]);
  const [marketStatus, setMarketStatus] = useState<MarketStatusData[]>([]);
  const [connected, setConnected] = useState(false);
  const [soundEnabled, setSoundEnabled] = useState(false);
  const [watchlist, setWatchlist] = useState<string[]>([]);
  const soundRef = useRef(soundEnabled);
  soundRef.current = soundEnabled;

  useEffect(() => {
    setWatchlist(loadWatchlist());
  }, []);

  const updateWatchlist = useCallback((tickers: string[]) => {
    setWatchlist(tickers);
    localStorage.setItem(WATCHLIST_KEY, JSON.stringify(tickers));
  }, []);

  useEffect(() => {
    fetchNews(1000).then(setItems).catch(() => {});
    fetchStats().then(setStats).catch(() => {});
    fetchIndices().then(setIndices).catch(() => {});
    fetchMarketStatus().then(setMarketStatus).catch(() => {});
  }, []);

  useEffect(() => {
    const si = setInterval(() => fetchStats().then(setStats).catch(() => {}), 30_000);
    const ii = setInterval(() => fetchIndices().then(setIndices).catch(() => {}), 30_000);
    const mi = setInterval(() => fetchMarketStatus().then(setMarketStatus).catch(() => {}), 60_000);
    return () => { clearInterval(si); clearInterval(ii); clearInterval(mi); };
  }, []);

  useEffect(() => {
    const es = createSSEConnection(
      (item) => {
        setItems((prev) => [item, ...prev]);
        if (isHighImpactAlert(item) && soundRef.current) {
          playAlertSound(item.sentiment === "positive" ? "positive" : "negative");
        }
      },
      () => setConnected(true),
      () => setConnected(false)
    );
    return () => es.close();
  }, []);

  const routed: RoutedNews = routeAllNews(items, watchlist);

  return (
    <div className="h-screen bg-[#080c08] flex flex-col overflow-hidden">
      <Header
        indices={indices}
        marketStatus={marketStatus}
        connected={connected}
        soundEnabled={soundEnabled}
        onToggleSound={() => setSoundEnabled((s) => !s)}
        totalItems={items.length}
      />
      <HighImpactStrip items={routed.highImpact} />

      <div className="flex-1 min-h-0">
        <Group direction="horizontal">
          <Panel id="left" order={1} defaultSize={35} minSize={20}>
            <Group direction="vertical">
              <Panel id="charts" order={1} defaultSize={45} minSize={15}>
                <div className="grid grid-cols-2 gap-2 p-2 h-full">
                  <SentimentDonut stats={stats} />
                  <NewsVelocity stats={stats} />
                </div>
              </Panel>
              <Separator />
              <Panel id="watchlist" order={2} defaultSize={55} minSize={15}>
                <div className="px-2 pb-2 h-full">
                  <WatchlistPanel
                    watchlist={watchlist}
                    onUpdateWatchlist={updateWatchlist}
                    watchlistItems={routed.watchlistItems}
                  />
                </div>
              </Panel>
            </Group>
          </Panel>
          <Separator />
          <Panel id="ticker-alerts" order={2} defaultSize={65} minSize={30}>
            <div className="p-2 pl-0 h-full">
              <NewsPanelCard
                title="Ticker Alerts"
                items={routed.tickerAlerts}
                emptyMessage="No ticker-specific alerts yet"
                showTickers
                enableSentimentFilter
              />
            </div>
          </Panel>
        </Group>
      </div>
    </div>
  );
}
